import{_ as d,o as r,c as a,a2 as h}from"./chunks/framework.Bkqnpl2X.js";const b=JSON.parse('{"title":"附录A 航空航天阀门设计校验清单（Design Verification Checklist, DVC）","description":"","frontmatter":{},"headers":[],"relativePath":"guide/appendix/appendix-a.md","filePath":"guide/appendix/appendix-a.md","lastUpdated":1780443280000}'),e={name:"guide/appendix/appendix-a.md"};function o(i,t,C,D,l,n){return r(),a("div",null,[...t[0]||(t[0]=[h('<h1 id="附录a-航空航天阀门设计校验清单-design-verification-checklist-dvc" tabindex="-1">附录A 航空航天阀门设计校验清单（Design Verification Checklist, DVC） <a class="header-anchor" href="#附录a-航空航天阀门设计校验清单-design-verification-checklist-dvc" aria-label="Permalink to &quot;附录A 航空航天阀门设计校验清单（Design Verification Checklist, DVC）&quot;">​</a></h1><p><strong>作者</strong>：小贤（航空航天阀门研发系统工程师，国际系统工程师CSEP，战略科学家） <strong>版本</strong>： V5.0 | <strong>类型</strong>：工具附录 | <strong>适用阶段</strong>：PDR后/CDR前设计审查</p><hr><h2 id="a-0-使用说明" tabindex="-1">A.0 使用说明 <a class="header-anchor" href="#a-0-使用说明" aria-label="Permalink to &quot;A.0 使用说明&quot;">​</a></h2><p>本设计校验清单（DVC）是手册各章设计约束的系统性汇总，用于在初步设计评审（PDR）之后、关键设计评审（CDR）之前，对阀门设计进行逐项自检。每条校验项分为三个等级：</p><ul><li><strong>M（Must，强制性）</strong>：违反将导致设计不合格——安全/任务关键约束，无任何豁免可能。</li><li><strong>S（Should，应满足）</strong>：违反需提交书面偏离申请（Deviation Request）并经总师审批——设计优化目标，有明确的工程代价。</li><li><strong>R（Recommended，推荐）</strong>：违反无需正式偏离申请但应在设计评审中说明理由——工程最佳实践。</li></ul><p>校验结果标记：</p><ul><li>✅ 通过</li><li>❌ 不通过（需整改）</li><li>⚠️ 条件通过（需额外分析或试验验证）</li><li>N/A 不适用</li></ul><p>设计师应在CDR评审前逐项完成本清单并签字，纳入设计档案。</p><hr><h2 id="a-1-总体设计与系统工程-对应第41-52章检查要点" tabindex="-1">A.1 总体设计与系统工程（对应第41-52章检查要点） <a class="header-anchor" href="#a-1-总体设计与系统工程-对应第41-52章检查要点" aria-label="Permalink to &quot;A.1 总体设计与系统工程（对应第41-52章检查要点）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>编号</th><th>校验项</th><th>等级</th><th>通过标准</th><th>核查方法</th><th>结果</th></tr></thead><tbody><tr><td>DVC-01</td><td>阀门在所有任务阶段（发射/在轨/变轨/推进/再入/着陆）的功能需求已逐阶段确认</td><td>M</td><td>每个任务阶段对应至少一个功能需求条目（FRD），且FRD与设计参数之间存在可验证的追溯矩阵</td><td>需求追溯矩阵审查</td><td></td></tr><tr><td>DVC-02</td><td>对阀门定义的所有性能指标（流量/响应时间/泄漏率/寿命/功耗）逐一验证了&quot;要求值→设计值→安全裕度&quot;的传递链</td><td>M</td><td>每项性能指标：设计值÷要求值≥安全裕度（见DVC-03），或通过FEA/CFD/试验证明了等价的性能保障</td><td>逐项性能裕度表格审查</td><td></td></tr><tr><td>DVC-03</td><td>安全裕度满足本手册第41章标准（见表A.1-1）</td><td>M</td><td>见表A.1-1</td><td>安全裕度报告审查</td><td></td></tr><tr><td>DVC-04</td><td>阀门FMECA（故障模式影响及危害性分析）已执行，所有Ⅰ类（灾难性）和Ⅱ类（关键）失效模式的缓解措施已落实</td><td>M</td><td>无Ⅰ/Ⅱ类失效模式处于&quot;无缓解&quot;状态</td><td>FMECA报告审查</td><td></td></tr><tr><td>DVC-05</td><td>阀门FTA（故障树分析）——针对&quot;阀门未能执行任务功能&quot;顶事件——的所有最小割集均被识别并有对应的&quot;设计对策&quot;或&quot;在轨应急预案&quot;</td><td>M</td><td>顶事件的未覆盖概率≤1×10⁻⁴/任务</td><td>FTA报告审查</td><td></td></tr><tr><td>DVC-06</td><td>阀门接口控制文件（ICD）已与上下游签署——涵盖机械接口（法兰/螺纹/密封）、电气接口（连接器/电压/电流/时序）、流体接口（介质/压力/流量/洁净度）</td><td>M</td><td>ICD三方（阀门设计师+上游+下游）签字确认</td><td>ICD签字页审查</td><td></td></tr><tr><td>DVC-07</td><td>阀门设计方案满足&quot;单点故障（SPF）容忍度&quot;要求——若任务要求SPF=0（不容忍任何SPF），阀门是否实现了功能冗余（如双线圈/双密封/并联冗余）？</td><td>S</td><td>SPF分析报告+NSTS 22206 SPF检查表</td><td>SPF分析报告审查</td><td></td></tr><tr><td>DVC-08</td><td>阀门质量预算（含管路接头和紧固件）与卫星/飞行器总的质量分配一致（含10%余量）</td><td>M</td><td>实际质量≤分配质量×1.10</td><td>CAD质量属性提取+实物称重（鉴定件）</td><td></td></tr><tr><td>DVC-09</td><td>阀门包络尺寸与卫星/飞行器的给定安装空间一致（含25mm最小操作间隙）</td><td>M</td><td>三维CAD装配干涉检查无碰撞</td><td>装配干涉检查报告</td><td></td></tr><tr><td>DVC-10</td><td>阀门的自然频率（基频）高于飞行器结构的最低要求频率（如运载火箭要求≥35Hz或≥100Hz，视安装位置而定）</td><td>M</td><td>FEA模态分析+（鉴定阶段）正弦扫频试验验证</td><td>FEA模态报告+振动试验报告</td><td></td></tr></tbody></table><hr><h3 id="表a-1-1-阀门安全裕度标准" tabindex="-1">表A.1-1：阀门安全裕度标准 <a class="header-anchor" href="#表a-1-1-阀门安全裕度标准" aria-label="Permalink to &quot;表A.1-1：阀门安全裕度标准&quot;">​</a></h3><table tabindex="0"><thead><tr><th>失效模式</th><th>最低安全裕度（鉴定件）</th><th>最低安全裕度（验收件）</th><th>分析方法</th></tr></thead><tbody><tr><td>承压壳体爆破/破裂</td><td>≥1.50（极限压力）</td><td>≥1.25（极限压力）</td><td>FEA + 液压爆破试验</td></tr><tr><td>承压壳体屈服</td><td>≥1.25（屈服压力）</td><td>≥1.10（屈服压力）</td><td>FEA + 应变片验证</td></tr><tr><td>紧固件断裂</td><td>≥1.40（极限载荷）</td><td>≥1.15（极限载荷）</td><td>手算/FEA + 接头试验</td></tr><tr><td>弹簧疲劳断裂</td><td>≥1.33（无限寿命设计）或 ≥1.1×（任务循环次数）</td><td>同鉴定</td><td>Goodman/Soderberg疲劳分析 + 疲劳试验</td></tr><tr><td>密封面泄漏（结构变形导致）</td><td>FEA变形量≤密封件补偿能力的50%</td><td>同鉴定</td><td>FEA + 氦检漏试验</td></tr><tr><td>焊缝断裂</td><td>≥1.40（极限载荷，计入焊趾应力集中系数）</td><td>≥1.15（极限载荷）</td><td>FEA + 焊缝试样拉伸</td></tr><tr><td>电磁力不足（阀门无法开启）</td><td>最小电压（含母线压降）×0.8下的电磁力 ≥ 阀门开启所需力的1.5倍</td><td>同鉴定</td><td>电磁FEA + 动作试验</td></tr></tbody></table><hr><h2 id="a-2-材料选择-对应第5-8、29-36章检查要点" tabindex="-1">A.2 材料选择（对应第5-8、29-36章检查要点） <a class="header-anchor" href="#a-2-材料选择-对应第5-8、29-36章检查要点" aria-label="Permalink to &quot;A.2 材料选择（对应第5-8、29-36章检查要点）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>编号</th><th>校验项</th><th>等级</th><th>通过标准</th><th>核查方法</th><th>结果</th></tr></thead><tbody><tr><td>DVC-11</td><td>所有与介质接触的材料已完成介质相容性评审——确认无应力腐蚀开裂（SCC）、无化学腐蚀、无氢脆</td><td>M</td><td>材料-介质相容性矩阵（MSFC-STD-3029或等效标准）显示所有接触对为&quot;A类&quot;（可接受）或&quot;B类&quot;（有条件接受+已验证）</td><td>相容性矩阵审查</td><td></td></tr><tr><td>DVC-12</td><td>金属材料的选择考虑了氢环境脆化（HEE）风险——若介质含氢（如液氢、肼分解产物氢）或工作在高压氢环境中</td><td>M</td><td>材料满足NASA-STD-6016的氢相容性等级要求，或已通过高压氢环境材料试验</td><td>材料证明文件+试验报告</td><td></td></tr><tr><td>DVC-13</td><td>非金属密封材料（O形圈/垫片/阀座）的贮存寿命≥任务寿命+地面贮存期+12个月余量</td><td>S</td><td>制造商证明文件或加速老化试验报告</td><td>材料寿命证明</td><td></td></tr><tr><td>DVC-14</td><td>非金属材料的出气率满足任务要求——TML≤1.0%且CVCM≤0.1%（按ASTM E595）</td><td>M（真空环境）/ S（非真空）</td><td>ASTM E595试验报告</td><td>出气试验报告</td><td></td></tr><tr><td>DVC-15</td><td>弹簧材料的应力松弛率在寿命周期内（含温度极值下的蠕变）不超过设计补偿能力的50%</td><td>S</td><td>应力松弛试验或公开材料数据+计算分析</td><td>松弛分析报告</td><td></td></tr><tr><td>DVC-16</td><td>焊接材料的匹配——填充金属与母材的强度匹配（等强或超强）与耐蚀性经评审</td><td>M</td><td>焊接工艺规程（WPS）+焊接工艺评定记录（PQR）</td><td>WPS/PQR审查</td><td></td></tr><tr><td>DVC-17</td><td>材料采购规范（采购技术条件）明确标明了热处理状态、力学性能验收指标、无损检测要求和拒收标准</td><td>M</td><td>材料采购规范文件</td><td>采购规范审查</td><td></td></tr></tbody></table><hr><h2 id="a-3-密封设计-对应第12-14、18-20、23-26章检查要点" tabindex="-1">A.3 密封设计（对应第12-14、18-20、23-26章检查要点） <a class="header-anchor" href="#a-3-密封设计-对应第12-14、18-20、23-26章检查要点" aria-label="Permalink to &quot;A.3 密封设计（对应第12-14、18-20、23-26章检查要点）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>编号</th><th>校验项</th><th>等级</th><th>通过标准</th><th>核查方法</th><th>结果</th></tr></thead><tbody><tr><td>DVC-18</td><td>密封面的泄漏率设计要求（外部泄漏+内部泄漏）在常温、高温、低温三个温度点均有明确量值，且每个量值均有验证方法</td><td>M</td><td>设计文件中有&quot;温度-泄漏率&quot;表，且每个温度点对应一个试验验证计划</td><td>密封设计报告审查</td><td></td></tr><tr><td>DVC-19</td><td>O形圈密封的压缩率（挤压率）在NASA手册或等同标准（如MIL-HDBK-338或Parker O-Ring Handbook）推荐范围内——典型静态密封15-25%、动态密封8-14%</td><td>S</td><td>O形圈压缩率计算（含公差叠加分析——最大材料+最小沟槽）</td><td>压缩率计算书</td><td></td></tr><tr><td>DVC-20</td><td>O形圈沟槽的填充率（O形圈截面积÷沟槽截面积）≤85%（避免过填充导致挤出）且≥60%（避免压缩不足）</td><td>S</td><td>填充率计算（含公差极端情况）</td><td>填充率计算书</td><td></td></tr><tr><td>DVC-21</td><td>PTFE/柔性石墨阀座密封的密封比压经FEA验证——在最小介质压差下满足&quot;密封所需最小接触应力&quot;，在最大介质压差下不超过材料的压缩强度</td><td>M</td><td>FEA接触应力分析+材料许用压缩应力对比</td><td>FEA密封分析报告</td><td></td></tr><tr><td>DVC-22</td><td>金属密封（C-ring/透镜垫/球面-锥面）的密封面表面粗糙度满足该密封型式的最小要求（如C-ring密封面Ra≤0.2μm，透镜垫座面Ra≤0.4μm）</td><td>M</td><td>表面粗糙度测量报告（轮廓仪/白光干涉仪）</td><td>粗糙度测量报告</td><td></td></tr><tr><td>DVC-23</td><td>密封面的硬度匹配——软密封方案中金属密封面的硬度≥非金属密封件硬度的3倍（避免金属面被压溃）；硬密封方案中两侧密封面的硬度差≥HRC10（避免粘着磨损）</td><td>S</td><td>硬度测量报告+计算对比</td><td>硬度匹配分析</td><td></td></tr><tr><td>DVC-24</td><td>波纹管密封（若适用）的疲劳寿命经FEA+试验验证——在全部任务循环次数（含50%附加余量）下无疲劳裂纹</td><td>M（若使用波纹管）</td><td>FEA疲劳分析+波纹管疲劳试验报告</td><td>波纹管疲劳验证</td><td></td></tr></tbody></table><hr><h2 id="a-4-流体力学设计-对应第9-11、16-17章检查要点" tabindex="-1">A.4 流体力学设计（对应第9-11、16-17章检查要点） <a class="header-anchor" href="#a-4-流体力学设计-对应第9-11、16-17章检查要点" aria-label="Permalink to &quot;A.4 流体力学设计（对应第9-11、16-17章检查要点）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>编号</th><th>校验项</th><th>等级</th><th>通过标准</th><th>核查方法</th><th>结果</th></tr></thead><tbody><tr><td>DVC-25</td><td>阀门的流量系数Cv（或Kv）在最小开度和最大开度两个极限位置均有分析值（CFD/理论公式）或试验值</td><td>S</td><td>CFD报告或流量试验报告</td><td>流量分析/试验报告</td><td></td></tr><tr><td>DVC-26</td><td>阀门全开时内部流场无超音速区（激波）——若不可避免，超音速区不产生有害的气动噪声或结构激振</td><td>S</td><td>CFD分析——马赫数云图</td><td>CFD报告</td><td></td></tr><tr><td>DVC-27</td><td>阀门全开时的压损（ΔP）满足系统分配的压损预算（通常&lt;5-10%系统总压，视任务要求）</td><td>M</td><td>CFD/试验验证</td><td>压损分析报告</td><td></td></tr><tr><td>DVC-28</td><td>阀门在关闭过程中的水锤压力峰值不损害阀体/管路（通常≤1.5倍工作压力）</td><td>S</td><td>水锤分析（特征线法或CFD瞬态分析）</td><td>水锤分析报告</td><td></td></tr><tr><td>DVC-29</td><td>阀门内流道无死区——所有区域在最大流速下有足够的冲刷速度（避免推进剂残留/污染物积聚）</td><td>R</td><td>CFD流线图——确认无回流死区</td><td>CFD报告</td><td></td></tr></tbody></table><hr><h2 id="a-5-驱动设计——电磁-气动-电动-对应第6-7、21-23章检查要点" tabindex="-1">A.5 驱动设计——电磁/气动/电动（对应第6-7、21-23章检查要点） <a class="header-anchor" href="#a-5-驱动设计——电磁-气动-电动-对应第6-7、21-23章检查要点" aria-label="Permalink to &quot;A.5 驱动设计——电磁/气动/电动（对应第6-7、21-23章检查要点）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>编号</th><th>校验项</th><th>等级</th><th>通过标准</th><th>核查方法</th><th>结果</th></tr></thead><tbody><tr><td>DVC-30</td><td>电磁阀在最低母线电压（含最恶劣的电压跌落和线路压降——通常额定电压的-20%）下能可靠动作（至少1.5倍安全系数于所需力/力矩）</td><td>M</td><td>电磁FEA+试验——动作电压测试</td><td>电磁分析+动作试验报告</td><td></td></tr><tr><td>DVC-31</td><td>电磁阀线圈温升在最恶劣工况（最高环境温度+最大通电时间+最大电流）下不超过线圈绝缘等级的许用温升（如H级绝缘180°C）</td><td>M</td><td>热分析+温度试验</td><td>热分析+线圈温升试验</td><td></td></tr><tr><td>DVC-32</td><td>电磁线圈的绝缘电阻在验收条件下≥100MΩ（500VDC）且在湿热试验后≥10MΩ</td><td>M</td><td>绝缘电阻测试</td><td>绝缘测试报告</td><td></td></tr><tr><td>DVC-33</td><td>气动阀的作动气源压力（最小/最大）在设计文件中明确，且在最小气源压力下能可靠驱动阀门全行程</td><td>M</td><td>气动计算+试验验证</td><td>气动分析+试验报告</td><td></td></tr><tr><td>DVC-34</td><td>电动阀（电机驱动）的电机转矩-速度曲线在全温范围内（含低温下润滑剂粘度增加）满足阀门驱动需求</td><td>M</td><td>电机性能曲线+减速器效率计算</td><td>电机选型分析报告</td><td></td></tr><tr><td>DVC-35</td><td>位置反馈传感器（如LVDT、接近开关）在全温范围内的精度和重复性满足任务的位置监控要求</td><td>S</td><td>传感器数据手册+温度试验验证</td><td>传感器精度分析</td><td></td></tr><tr><td>DVC-36</td><td>冗余驱动（双线圈/双电机）的切换逻辑经FMEA验证——单线圈故障不导致阀位错误</td><td>M（若使用冗余）</td><td>FMEA+故障注入试验</td><td>冗余切换试验报告</td><td></td></tr></tbody></table><hr><h2 id="a-6-制造与质量保证-对应第18-20、28章检查要点" tabindex="-1">A.6 制造与质量保证（对应第18-20、28章检查要点） <a class="header-anchor" href="#a-6-制造与质量保证-对应第18-20、28章检查要点" aria-label="Permalink to &quot;A.6 制造与质量保证（对应第18-20、28章检查要点）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>编号</th><th>校验项</th><th>等级</th><th>通过标准</th><th>核查方法</th><th>结果</th></tr></thead><tbody><tr><td>DVC-37</td><td>所有承压焊缝有对应的焊接工艺评定记录（PQR）且覆盖了产品的材料、厚度范围和焊接位置</td><td>M</td><td>WPS/PQR矩阵——无遗漏</td><td>WPS/PQR审查</td><td></td></tr><tr><td>DVC-38</td><td>承压焊缝100%经无损检测（RT或UT）+表面检测（PT或MT）——内部缺陷标准按ASME B31.3或等同标准验收</td><td>M</td><td>NDT报告</td><td>NDT报告审查</td><td></td></tr><tr><td>DVC-39</td><td>所有关键尺寸（密封面直径/同轴度/表面粗糙度/行程/弹簧预紧力/电磁气隙）在图纸中明确标注公差，且公差链分析证明装配后满足功能需求</td><td>M</td><td>公差链分析报告（WC或RSS方法）</td><td>公差分析报告</td><td></td></tr><tr><td>DVC-40</td><td>清洁度控制——所有与介质接触的表面在最终装配前经规定的清洗工艺（如超声波清洗+去离子水冲洗+烘干），目视检验无可见污染物</td><td>M</td><td>清洗工艺文件+清洁度检验记录（含颗粒计数，如适用）</td><td>清洗记录审查</td><td></td></tr><tr><td>DVC-41</td><td>产品标识与可追溯性——阀门和关键零件（阀体/阀芯/密封件批次）上有永久标识，可追溯到原材料批次和加工过程</td><td>M</td><td>标识检查清单</td><td>标识实物检查</td><td></td></tr></tbody></table><hr><h2 id="a-7-试验验证-对应第44-50、54-55章检查要点" tabindex="-1">A.7 试验验证（对应第44-50、54-55章检查要点） <a class="header-anchor" href="#a-7-试验验证-对应第44-50、54-55章检查要点" aria-label="Permalink to &quot;A.7 试验验证（对应第44-50、54-55章检查要点）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>编号</th><th>校验项</th><th>等级</th><th>通过标准</th><th>核查方法</th><th>结果</th></tr></thead><tbody><tr><td>DVC-42</td><td>验收试验（ATP）覆盖全部关键性能参数——动作/泄漏/耐压/绝缘——每一件产品发货前100%执行</td><td>M</td><td>ATP程序文件+每件产品的ATP报告</td><td>ATP报告审查</td><td></td></tr><tr><td>DVC-43</td><td>鉴定试验（QTP）矩阵覆盖所有任务环境——振动/冲击/热真空/EMC/寿命/湿热/盐雾（视任务需要）</td><td>M</td><td>QTP程序文件+QTP报告——无遗漏项</td><td>QTP报告审查</td><td></td></tr><tr><td>DVC-44</td><td>振动试验——随机振动谱（按任务特定的PSD）+正弦扫频——试验后功能正常且无结构损坏</td><td>M</td><td>振动试验报告+试验前后性能对比</td><td>振动试验报告</td><td></td></tr><tr><td>DVC-45</td><td>热真空/热循环试验——温度极值（含±10°C裕度）下工作正常，热循环次数≥任务剖面的温度循环次数×3</td><td>M（真空环境）</td><td>热真空试验报告</td><td>热真空试验报告</td><td></td></tr><tr><td>DVC-46</td><td>氦质谱检漏——阀门外部泄漏和内部泄漏在验收/鉴定试验的各个阶段（常温/高温/低温/振动前后/寿命试验前后）均有检测</td><td>M</td><td>氦检漏报告——逐阶段</td><td>检漏报告审查</td><td></td></tr><tr><td>DVC-47</td><td>寿命试验——≥1.5倍任务循环次数（若有可靠性要求则为≥4倍）——试验后泄漏率和动作性能仍在规范内</td><td>M</td><td>寿命试验报告</td><td>寿命试验报告</td><td></td></tr><tr><td>DVC-48</td><td>EMC试验——CE/CS/RE/RS（传导发射/传导敏感度/辐射发射/辐射敏感度）——满足GJB151B/MIL-STD-461（或等效任务标准）</td><td>M（若有电子部件）</td><td>EMC试验报告</td><td>EMC试验报告</td><td></td></tr><tr><td>DVC-49</td><td>试验异常与偏差——任何ATP/QTP中出现的异常（包括可复现的性能偏差）均已完成归零分析（Root Cause Analysis），整改措施已落实且在回归试验中验证</td><td>M</td><td>归零报告+回归试验报告</td><td>归零报告审查</td><td></td></tr></tbody></table><hr><h2 id="a-8-特殊工况-对应第32-36、56-58章检查要点" tabindex="-1">A.8 特殊工况（对应第32-36、56-58章检查要点） <a class="header-anchor" href="#a-8-特殊工况-对应第32-36、56-58章检查要点" aria-label="Permalink to &quot;A.8 特殊工况（对应第32-36、56-58章检查要点）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>编号</th><th>校验项</th><th>等级</th><th>通过标准</th><th>核查方法</th><th>结果</th></tr></thead><tbody><tr><td>DVC-50</td><td>低温工况（液氧90K/液氢20K/液甲烷112K）——所有材料的低温力学性能（特别是韧脆转变——A_kv≥要求值）经评审/试验</td><td>M（若低温工况）</td><td>材料低温性能证明</td><td>低温材料报告</td><td></td></tr><tr><td>DVC-51</td><td>高温工况（&gt;300°C）——弹簧松弛和密封材料高温性能经评审/试验</td><td>M（若高温工况）</td><td>高温材料试验报告</td><td>高温材料验证</td><td></td></tr><tr><td>DVC-52</td><td>腐蚀性介质（如N₂O₄、MON-3、HAN基推进剂）——所有接触材料通过长期浸泡腐蚀试验（通常≥1000h）</td><td>M（若腐蚀介质）</td><td>腐蚀试验报告</td><td>腐蚀试验报告</td><td></td></tr><tr><td>DVC-53</td><td>绿色推进剂（如AF-M315E、LMP-103S、HAN基）——非金属材料相容性经专门评审（绿色推进剂与肼类的化学攻击机制不同——氧化性更强）</td><td>M（若使用绿色推进剂）</td><td>绿色推进剂相容性试验矩阵</td><td>材料相容性试验</td><td></td></tr><tr><td>DVC-54</td><td>核电推进环境——阀门的辐射耐受（总剂量+单粒子）经评审——电子元件满足辐射加固等级，非金属材料满足辐射老化要求</td><td>M（若核电推进）</td><td>辐射分析+元件辐射证明</td><td>辐射分析报告</td><td></td></tr></tbody></table><hr><h2 id="a-9-人工智能辅助设计-对应第59章检查要点" tabindex="-1">A.9 人工智能辅助设计（对应第59章检查要点） <a class="header-anchor" href="#a-9-人工智能辅助设计-对应第59章检查要点" aria-label="Permalink to &quot;A.9 人工智能辅助设计（对应第59章检查要点）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>编号</th><th>校验项</th><th>等级</th><th>通过标准</th><th>核查方法</th><th>结果</th></tr></thead><tbody><tr><td>DVC-55</td><td>若使用了AI/ML辅助的参数优化或拓扑优化——优化结果经独立FEA验证（不直接采信AI输出）</td><td>M（若使用AI辅助）</td><td>独立FEA报告——确认AI优化结果物理合理性</td><td>FEA验证报告</td><td></td></tr><tr><td>DVC-56</td><td>AI/ML训练数据集的覆盖范围（参数空间）包含了本阀门设计点的全部工况？</td><td>S（若使用AI辅助）</td><td>数据集覆盖性分析</td><td>数据集审查</td><td></td></tr></tbody></table><hr><h2 id="a-10-成本工程-对应第60章检查要点" tabindex="-1">A.10 成本工程（对应第60章检查要点） <a class="header-anchor" href="#a-10-成本工程-对应第60章检查要点" aria-label="Permalink to &quot;A.10 成本工程（对应第60章检查要点）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>编号</th><th>校验项</th><th>等级</th><th>通过标准</th><th>核查方法</th><th>结果</th></tr></thead><tbody><tr><td>DVC-57</td><td>阀门设计方案已完成面向成本的设计（DTC）评审——至少审查了以下三项降本机会：(1)减少零件数量；(2)标准件替代非标件；(3)简化加工工艺</td><td>R</td><td>DTC评审会议纪要</td><td>DTC评审纪要</td><td></td></tr><tr><td>DVC-58</td><td>对于商业航天项目，阀门单位成本是否在项目成本预算目标内（含≥10%应急储备）？</td><td>R（商业航天）/ S（政府项目）</td><td>成本估算报告（工程估算法）</td><td>成本报告审查</td><td></td></tr></tbody></table><hr><h2 id="附录a参考文献" tabindex="-1">附录A参考文献 <a class="header-anchor" href="#附录a参考文献" aria-label="Permalink to &quot;附录A参考文献&quot;">​</a></h2><table tabindex="0"><thead><tr><th>编号</th><th>标准/文献</th><th>涉及DVC编号</th></tr></thead><tbody><tr><td>1</td><td>MSFC-STD-3029, Materials and Processes Compatibility</td><td>DVC-11, DVC-52</td></tr><tr><td>2</td><td>NASA-STD-6016, Hydrogen Compatibility of Materials</td><td>DVC-12</td></tr><tr><td>3</td><td>ASTM E595, Outgassing Test</td><td>DVC-14</td></tr><tr><td>4</td><td>Parker O-Ring Handbook (ORD 5700)</td><td>DVC-19, DVC-20</td></tr><tr><td>5</td><td>ASME B31.3, Process Piping</td><td>DVC-38</td></tr><tr><td>6</td><td>GJB 151B / MIL-STD-461, EMC</td><td>DVC-48</td></tr><tr><td>7</td><td>NSTS 22206, Single Failure Point</td><td>DVC-07</td></tr><tr><td>8</td><td>MIL-HDBK-338, Reliability Design Handbook</td><td>DVC-04, DVC-05</td></tr><tr><td>9</td><td>MIL-HDBK-881E, WBS for Defense</td><td>DVC-57, DVC-58</td></tr></tbody></table><hr><blockquote><p><strong>编写说明——2026年6月V5.0新增</strong>：本附录根据V4.0项目成果报告后续建议第3条（&quot;设计校验清单&quot;）编制。从Avis手册各章节的设计约束中提取并整合为58条校验项，覆盖总体设计（DVC-01~10）、材料选择（DVC-11~17）、密封设计（DVC-18~24）、流体力学（DVC-25~29）、驱动设计（DVC-30~36）、制造质量（DVC-37~41）、试验验证（DVC-42~49）、特殊工况（DVC-50~54）、AI辅助设计（DVC-55~56）、成本工程（DVC-57~58）共10个维度，供PDR后/CDR前的设计审查使用。</p></blockquote>',47)])])}const A=d(e,[["render",o]]);export{b as __pageData,A as default};
